### Código para tu `server.js` (Backend)

Copia esto en un archivo `server.js` en tu carpeta del proyecto:

```javascript
const express = require('express');
const mysql = require('mysql2');
const cors = require('cors');
const bodyParser = require('body-parser');

const app = express();
app.use(cors());
app.use(bodyParser.json());

// CONFIGURA TU CONEXIÓN SQL AQUÍ
const db = mysql.createConnection({
  host: 'localhost',      // O tu IP del servidor
  user: 'root',           // Tu usuario SQL
  password: 'tu_password',// Tu contraseña SQL
  database: 'nombre_tu_bd'// El nombre de tu base de datos
});

db.connect(err => {
  if (err) console.error('Error conectando a SQL:', err);
  else console.log('Conectado a MySQL');
});

// --- ENDPOINTS (API) ---

// Obtener Instituciones
app.get('/api/instituciones', (req, res) => {
  db.query('SELECT * FROM instituciones', (err, results) => {
    if (err) return res.status(500).send(err);
    res.json(results);
  });
});

// Obtener Ofertas (Con JOINS para armar el objeto completo)
app.get('/api/ofertas', (req, res) => {
  const sql = `
    SELECT o.id_oferta, 
           i.nombre as inst_nombre, i.id_institucion,
           c.nombre as carrera_nombre,
           n.nombre as nivel_nombre
           -- Agrega aquí el resto de campos que necesites con JOINs
    FROM ofertas o
    JOIN instituciones i ON o.id_institucion = i.id_institucion
    JOIN carreras c ON o.id_carrera = c.id_carrera
    JOIN niveles n ON o.id_nivel = n.id_nivel
  `;
  db.query(sql, (err, results) => {
    if (err) return res.status(500).send(err);

    // Mapeo simple para ajustar al formato que espera React
    const formatted = results.map(r => ({
        id_oferta: r.id_oferta,
        institucion: { id_institucion: r.id_institucion, nombre: r.inst_nombre },
        carrera: { nombre: r.carrera_nombre },
        nivel: { nombre: r.nivel_nombre },
        // ... rellenar resto de datos
    }));
    res.json(formatted);
  });
});

// Login
app.post('/api/login', (req, res) => {
    const { role, email, accessCode } = req.body;

    if (role === 'institution') {
        // Ejemplo simple: Verificar código hardcodeado o buscar en tabla usuarios
        if (accessCode === 'UTSJR-ADMIN') {
             return res.json({ id: 1, name: 'Admin UTSJR', role: 'institution' });
        }
        return res.status(401).json({ message: 'Código inválido' });
    }
    // Login estudiante (demo)
    res.json({ id: 99, name: 'Estudiante', role: 'student' });
});

app.listen(3000, () => {
  console.log('Servidor corriendo en puerto 3000');
});

El error que te aparece (`no such file or directory` y `Cannot find module`) ocurre por dos razones sencillas:

1.  **Espacios en el nombre:** Tienes una carpeta llamada `aide proyecto`. En la terminal, los espacios rompen el comando a menos que uses comillas.
2.  **Faltó el comando `cd`:** Escribiste la ruta directa, pero para entrar a ella necesitas escribir `cd` antes.

Vamos a arreglarlo paso a paso. **Copia y pega** estos comandos en tu terminal uno por uno:

### Paso 1: Crear las carpetas y entrar (Corregido)

Copia esto en tu terminal y dale Enter:

```bash
mkdir -p "$HOME/Documents/aide proyecto/MiProyectoUniversidades/backend"
cd "$HOME/Documents/aide proyecto/MiProyectoUniversidades/backend"
```

*(Ahora deberías ver que el texto a la izquierda de tu cursor cambió, indicando que estás dentro de la carpeta `backend`)*.

### Paso 2: Instalar las herramientas (Node.js)

Ahora que estás dentro, ejecuta estos comandos uno por uno:

```bash
npm init -y
```

*(Esto creará un archivo package.json)*.

```bash
npm install express mysql2 cors body-parser
```

*(Verás una barra de carga instalando las librerías)*.

### Paso 3: Crear el archivo `server.js`

Ahora necesitas crear el archivo del servidor. Puedes hacerlo desde tu editor de código (VS Code) o ejecutar este comando en la terminal para crear el archivo vacío y luego pegarle el código:

```bash
touch server.js
open -a TextEdit server.js
```

*(Esto abrirá un editor de texto simple).*

Copia el siguiente código, pégalo en ese archivo y **GUÁRDALO** (Cmd + S):

```javascript
const express = require('express');
const mysql = require('mysql2');
const cors = require('cors');
const bodyParser = require('body-parser');

const app = express();
app.use(cors());
app.use(bodyParser.json());

// --- CONFIGURA TU CONEXIÓN AQUÍ ---
const db = mysql.createConnection({
  host: 'localhost',
  user: 'root',       // Tu usuario SQL (root es el default en XAMPP/MAMP)
  password: '',       // Tu contraseña SQL (déjalo vacío si no tienes)
  database: 'unimap_db' // IMPORTANTE: Asegúrate de haber creado esta BD
});

db.connect(err => {
  if (err) {
    console.error('❌ Error conectando a SQL:', err.message);
    console.log('TIP: ¿Está encendido tu MySQL (XAMPP/MAMP)? ¿Creaste la base de datos "unimap_db"?');
  } else {
    console.log('✅ Conectado a MySQL correctamente');
  }
});

// --- API ENDPOINTS ---

app.get('/api/instituciones', (req, res) => {
  db.query('SELECT * FROM instituciones', (err, results) => {
    if (err) return res.status(500).send(err);
    res.json(results);
  });
});

app.get('/api/ofertas', (req, res) => {
  // JOIN para traer nombres en lugar de solo IDs
  const sql = `
    SELECT o.id_oferta, 
           i.nombre as inst_nombre, i.id_institucion, i.latitud, i.longitud,
           c.nombre as carrera_nombre, c.clave,
           n.nombre as nivel_nombre,
           m.nombre as modalidad_nombre,
           mun.nombre as municipio_nombre,
           e.nombre as escuela_nombre, e.duracion
    FROM ofertas o
    JOIN instituciones i ON o.id_institucion = i.id_institucion
    JOIN carreras c ON o.id_carrera = c.id_carrera
    JOIN niveles n ON o.id_nivel = n.id_nivel
    JOIN modalidades m ON o.id_modalidad = m.id_modalidad
    JOIN municipios mun ON i.id_municipio = mun.id_municipio -- Asumiendo relación simple por institución
    JOIN escuelas e ON o.id_escuela = e.id_escuela
  `;

  // Nota: Si tus relaciones SQL son diferentes, ajusta los JOINs de arriba

  db.query(sql, (err, results) => {
    if (err) {
        // Si falla el query complejo, intentamos uno simple para debug
        console.error("Error en query ofertas:", err);
        return res.status(500).send(err);
    }

    // Formatear para React
    const formatted = results.map(r => ({
        id_oferta: r.id_oferta,
        institucion: { id_institucion: r.id_institucion, nombre: r.inst_nombre, latitud: r.latitud, longitud: r.longitud },
        carrera: { nombre: r.carrera_nombre, clave: r.clave },
        nivel: { nombre: r.nivel_nombre },
        modalidad: { nombre: r.modalidad_nombre },
        municipio: { nombre: r.municipio_nombre || 'N/A' },
        escuela: { nombre: r.escuela_nombre, duracion: r.duracion }
    }));
    res.json(formatted);
  });
});

// Catálogos para filtros
app.get('/api/municipios', (req, res) => {
    db.query('SELECT * FROM municipios', (err, resuls) => { if(!err) res.json(resuls); });
});
app.get('/api/niveles', (req, res) => {
    db.query('SELECT * FROM niveles', (err, resuls) => { if(!err) res.json(resuls); });
});
app.get('/api/campos', (req, res) => {
    db.query('SELECT * FROM campos_formacion', (err, resuls) => { if(!err) res.json(resuls); });
});
app.get('/api/modalidades', (req, res) => {
    db.query('SELECT * FROM modalidades', (err, resuls) => { if(!err) res.json(resuls); });
});

// Login Simulado
app.post('/api/login', (req, res) => {
    const { role, email, accessCode } = req.body;
    console.log(`Intento de login: ${role} - ${email}`);

    if (role === 'institution') {
        if (accessCode === 'UTSJR-ADMIN') {
             return res.json({ id: 1, name: 'Admin UTSJR', role: 'institution' });
        }
        if (accessCode === 'UAQ-ADMIN') {
             return res.json({ id: 2, name: 'Admin UAQ', role: 'institution' });
        }
        return res.status(401).json({ message: 'Código de acceso inválido' });
    }
    res.json({ id: 99, name: 'Estudiante', role: 'student' });
});

app.listen(3000, () => {
  console.log('🚀 Servidor corriendo en http://localhost:3000');
});
```

### Paso 4: Encender el servidor

Vuelve a la terminal (donde estás en la carpeta backend) y escribe:

```bash
node server.js
```

Si todo sale bien, dirá: `🚀 Servidor corriendo en http://localhost:3000` y `✅ Conectado a MySQL correctamente`.

**¡No cierres esa ventana de la terminal!** Ese es tu servidor funcionando.

---

### Siguiente paso: El Frontend (La Web)

Ahora abre **otra ventana nueva de terminal** (Cmd + T o Nueva Ventana) y haz lo siguiente para instalar la parte visual:

```bash
mkdir -p "$HOME/Documents/aide proyecto/MiProyectoUniversidades/frontend"
cd "$HOME/Documents/aide proyecto/MiProyectoUniversidades/frontend"
npm create vite@latest . -- --template react-ts
npm install
npm install lucide-react react-router-dom leaflet react-leaflet tailwindcss postcss autoprefixer
npx tailwindcss init -p
```

Cuando llegues a este punto, avísame y te diré dónde copiar los archivos `.tsx` que generé.

Veo que te has quedado atascado en el paso 2 por un problema de **rutas en la terminal** (los espacios en "aide proyecto" causan error) y porque tu configuración de MySQL en Mac requiere un **Socket** específico.

No te preocupes, vamos a solucionarlo.

### 1. Solución al Error de Terminal (Paso 2)

El error `no such file or directory` ocurre porque la terminal piensa que `aide` y `proyecto` son dos carpetas distintas. Debes usar comillas.

Escribe esto exactamente en tu terminal para entrar a la carpeta correcta:

```bash
cd "/Users/robertohernandez/Documents/aide proyecto/MiProyectoUniversidades/backend"
```

### 2. Actualización del Backend (`server.js`) con tus datos de SQL

Dado que me diste la información de tu conexión (Socket: `/tmp/mysql.sock`), **necesitas actualizar tu archivo `server.js`** para que funcione en tu Mac. El código anterior fallará porque Mac prefiere Sockets en lugar de `localhost` por puerto TCP.

Crea o edita el archivo `server.js` dentro de esa carpeta `backend` y pon este código exacto:

```javascript
const express = require('express');
const mysql = require('mysql2');
const cors = require('cors');
const bodyParser = require('body-parser');

const app = express();
app.use(cors());
app.use(bodyParser.json());

// CONFIGURACIÓN PARA TU MAC (Socket /tmp/mysql.sock)
const db = mysql.createConnection({
  socketPath: '/tmp/mysql.sock', // <--- ESTO ES LA CLAVE PARA TU MAC
  user: 'root',       
  password: '',       // En Homebrew/Mac suele ser vacía o 'root'
  database: 'unimap_db' // Asegúrate de haber creado esta base de datos
});

db.connect(err => {
  if (err) {
    console.error('❌ Error conectando a SQL:', err.message);
    console.log('Intenta crear la base de datos primero: CREATE DATABASE unimap_db;');
  } else {
    console.log('✅ Conectado a MySQL vía Socket correctamente');
  }
});

// --- API ENDPOINTS ---

app.get('/api/instituciones', (req, res) => {
  db.query('SELECT * FROM instituciones', (err, results) => {
    if (err) return res.status(500).send(err);
    res.json(results);
  });
});

app.get('/api/ofertas', (req, res) => {
  // Query con JOINS para traer nombres completos
  const sql = `
    SELECT o.id_oferta, 
           i.nombre as inst_nombre, i.id_institucion, i.latitud, i.longitud,
           c.nombre as carrera_nombre, c.clave,
           n.nombre as nivel_nombre,
           m.nombre as modalidad_nombre,
           mun.nombre as municipio_nombre,
           e.nombre as escuela_nombre, e.duracion
    FROM ofertas o
    JOIN instituciones i ON o.id_institucion = i.id_institucion
    JOIN carreras c ON o.id_carrera = c.id_carrera
    JOIN niveles n ON o.id_nivel = n.id_nivel
    JOIN modalidades m ON o.id_modalidad = m.id_modalidad
    JOIN municipios mun ON i.id_municipio = mun.id_municipio
    JOIN escuelas e ON o.id_escuela = e.id_escuela
  `;

  db.query(sql, (err, results) => {
    if (err) {
        console.error(err); 
        return res.status(500).send(err);
    }

    // Formatear respuesta para el Frontend
    const formatted = results.map(r => ({
        id_oferta: r.id_oferta,
        institucion: { id_institucion: r.id_institucion, nombre: r.inst_nombre, latitud: r.latitud, longitud: r.longitud },
        carrera: { nombre: r.carrera_nombre, clave: r.clave },
        nivel: { nombre: r.nivel_nombre },
        modalidad: { nombre: r.modalidad_nombre },
        municipio: { nombre: r.municipio_nombre || 'N/A' },
        escuela: { nombre: r.escuela_nombre, duracion: r.duracion }
    }));
    res.json(formatted);
  });
});

// Filtros
app.get('/api/municipios', (req, res) => { db.query('SELECT * FROM municipios', (e,r) => res.json(r)); });
app.get('/api/niveles', (req, res) => { db.query('SELECT * FROM niveles', (e,r) => res.json(r)); });
app.get('/api/campos', (req, res) => { db.query('SELECT * FROM campos_formacion', (e,r) => res.json(r)); });
app.get('/api/modalidades', (req, res) => { db.query('SELECT * FROM modalidades', (e,r) => res.json(r)); });

// Login
app.post('/api/login', (req, res) => {
    const { role, accessCode } = req.body;
    if (role === 'institution') {
        if (accessCode === 'UTSJR-ADMIN') return res.json({ id: 1, name: 'Admin UTSJR', role: 'institution' });
        return res.status(401).json({ message: 'Código inválido' });
    }
    res.json({ id: 99, name: 'Estudiante', role: 'student' });
});

app.listen(3000, () => {
  console.log('🚀 Servidor corriendo en http://localhost:3000');
});
```

Una vez guardado, ejecuta en la terminal: `node server.js`

---

### 3. Actualización del Frontend

He actualizado el código de la aplicación para que te avise visualmente si no logra conectar con tu servidor. Esto te ayudará a saber si el paso 2 funcionó o no.

Copia los archivos que has descargado en la carpeta:
`/Users/robertohernandez/Documents/aide proyecto/MiProyectoUniversidades/frontend/src`

Aquí están los cambios para ayudar a depurar la conexión:

El problema principal es que **tu base de datos MySQL está vacía** o el Backend no tiene una forma de recibir ese archivo `.sql` que tienes en tu carpeta.

Por eso ves la página "en blanco" o sin datos: el contenedor (Frontend) está listo, la tubería (Backend) está lista, pero no hay agua (Datos) en el tanque.

Vamos a solucionarlo habilitando un **Importador de Datos** directamente en la página web.

Sigue estos 3 pasos:

### PASO 1: Actualiza tu Backend (`server.js`)
Necesito enseñar a tu servidor cómo leer tu archivo SQL.

1.  Ve a tu carpeta `backend`.
2.  Abre el archivo `server.js`.
3.  **Borra todo** y pega este nuevo código que incluye la función de "Importar SQL":

```javascript
const express = require('express');
const mysql = require('mysql2');
const cors = require('cors');
const bodyParser = require('body-parser');

const app = express();
app.use(cors());
// Aumentamos el límite para permitir archivos SQL grandes
app.use(bodyParser.json({ limit: '50mb' }));
app.use(bodyParser.urlencoded({ limit: '50mb', extended: true }));

// CONFIGURACIÓN BASE DE DATOS (MAC)
const db = mysql.createConnection({
  socketPath: '/tmp/mysql.sock', 
  user: 'root',       
  password: '',       
  database: 'unimap_db',
  multipleStatements: true // <--- IMPORTANTE: Permite correr el script completo
});

db.connect(err => {
  if (err) {
    console.error('❌ Error SQL:', err.message);
  } else {
    console.log('✅ Conectado a MySQL (Socket)');
  }
});

// --- ENDPOINTS ---

app.get('/api/instituciones', (req, res) => {
  db.query('SELECT * FROM instituciones', (err, results) => {
    if (err) return res.status(500).send(err);
    res.json(results);
  });
});

app.get('/api/ofertas', (req, res) => {
  const sql = `
    SELECT o.id_oferta, 
           i.nombre as inst_nombre, i.id_institucion, i.latitud, i.longitud,
           c.nombre as carrera_nombre, c.clave,
           n.nombre as nivel_nombre,
           m.nombre as modalidad_nombre,
           mun.nombre as municipio_nombre,
           e.nombre as escuela_nombre, e.duracion
    FROM ofertas o
    JOIN instituciones i ON o.id_institucion = i.id_institucion
    JOIN carreras c ON o.id_carrera = c.id_carrera
    JOIN niveles n ON o.id_nivel = n.id_nivel
    JOIN modalidades m ON o.id_modalidad = m.id_modalidad
    JOIN municipios mun ON i.id_municipio = mun.id_municipio
    JOIN escuelas e ON o.id_escuela = e.id_escuela
  `;
  db.query(sql, (err, results) => {
    if (err) return res.status(500).send(err);

    const formatted = results.map(r => ({
        id_oferta: r.id_oferta,
        institucion: { id_institucion: r.id_institucion, nombre: r.inst_nombre, latitud: r.latitud, longitud: r.longitud },
        carrera: { nombre: r.carrera_nombre, clave: r.clave },
        nivel: { nombre: r.nivel_nombre },
        modalidad: { nombre: r.modalidad_nombre },
        municipio: { nombre: r.municipio_nombre || 'N/A' },
        escuela: { nombre: r.escuela_nombre, duracion: r.duracion }
    }));
    res.json(formatted);
  });
});

// NUEVO: Endpoint para importar SQL desde la web
app.post('/api/import', (req, res) => {
    const { sqlContent } = req.body;
    if (!sqlContent) return res.status(400).send("No SQL content");

    console.log("📥 Recibiendo archivo SQL...");

    // Ejecutar el script SQL completo
    db.query(sqlContent, (err, result) => {
        if (err) {
            console.error("Error importando SQL:", err);
            return res.status(500).json({ error: err.message });
        }
        console.log("✅ Importación exitosa");
        res.json({ message: "Base de datos actualizada correctamente" });
    });
});

// Filtros básicos
app.get('/api/municipios', (req, res) => { db.query('SELECT * FROM municipios', (e,r) => res.json(r || [])); });
app.get('/api/niveles', (req, res) => { db.query('SELECT * FROM niveles', (e,r) => res.json(r || [])); });
app.get('/api/campos', (req, res) => { db.query('SELECT * FROM campos_formacion', (e,r) => res.json(r || [])); });
app.get('/api/modalidades', (req, res) => { db.query('SELECT * FROM modalidades', (e,r) => res.json(r || [])); });

app.listen(3000, () => {
  console.log('🚀 Backend listo para importar datos en puerto 3000');
});
```
4.  Reinicia el servidor en la terminal: `Ctrl+C` y luego `node server.js`.

