                                    {availableModalidades.map(m => <option key={m} value={m}>{m}</option>)}
                                </select>
                                <select className="p-2 text-sm border border-slate-200 rounded-lg bg-white min-w-[120px]" value={offerCampo} onChange={e => setOfferCampo(e.target.value)}>
