                                    <option value="">Campus</option>
                                    {availableCampuses.map(c => <option key={c} value={c}>{c}</option>)}
                                </select>
                            </div>
                        </div>

                        <div className="space-y-3">
                            {filteredOffers.map((o, index) => (
                                <div 
                                    key={o.id_oferta} 
                                    onClick={() => handleOpenOffer(o)} 
