                                <span className="block text-2xl font-bold text-emerald-600">{[...new Set(ofertas.map(o => o.nivel.nombre))].length}</span>
                                <span className="text-[10px] text-slate-500 uppercase font-bold">Niveles</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>

