        setInstitucion(updated);
        setIsEditingProfile(false);
      } catch (e) { alert("Error al guardar cambios."); } finally { setIsSavingProfile(false); }
  };
  const handleSendInterest = async () => {
      if (!user || !institucion) return;
      setIsSendingInterest(true);
