      for (let y = 0; y <= 512; y += step) {
        if (ctx.isPointInPath(path, x, y)) {
          generatedDots.push({ x, y });
        }
      }
    }
    setDots(generatedDots);
    dotsRef.current = generatedDots;
  }, []);

  const spawnInfo = () => {
    if (dotsRef.current.length === 0) return;
    const randomData = educationalData[Math.floor(Math.random() * educationalData.length)];
    const startDot = dotsRef.current[Math.floor(Math.random() * dotsRef.current.length)];
    const outerPositions = [
      { x: 40, y: 120 }, { x: 470, y: 120 },
      { x: 40, y: 380 }, { x: 470, y: 380 },
      { x: 256, y: 30 }, { x: 256, y: 480 }
    ];
    const target = outerPositions[Math.floor(Math.random() * outerPositions.length)];
    const newInfo: EducationalInfo = {
      id: Date.now(),
      label: randomData.label,
      value: randomData.value,
      startX: startDot.x,
      startY: startDot.y,
      endX: target.x + (Math.random() * 60 - 30),
      endY: target.y + (Math.random() * 60 - 30),
    };
    setActiveInfo(prev => [...prev, newInfo].slice(-2));
  };

  useEffect(() => {
    const interval = setInterval(spawnInfo, 5000);
    spawnInfo();
    return () => clearInterval(interval);
  }, []);

  const handleStart = () => {
    setAnimateOut(true);
    setTimeout(() => {
      setVisible(false);
      onStart();
    }, 1000);
  };

  if (!visible) return null;

  return (
    <div className={`fixed inset-0 z-[9999] bg-[#050810] flex flex-col items-center justify-center overflow-hidden transition-all duration-1000 ${animateOut ? 'opacity-0 scale-110 blur-xl' : 'opacity-100'}`}>

      {/* Background Ambience */}
      <div className="absolute inset-0 pointer-events-none">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-indigo-500/5 blur-[120px] rounded-full"></div>
      </div>

      {/* Mexico Map Visual */}
      <div className="relative w-full max-w-4xl h-[400px] md:h-[550px] flex items-center justify-center mb-8">
        <svg 
          viewBox="0 0 512 512" 
          className="w-full h-full overflow-visible drop-shadow-[0_0_50px_rgba(99,102,241,0.1)]"
          xmlns="http://www.w3.org/2000/svg"
        >
          <defs>
            <filter id="softGlow" x="-50%" y="-50%" width="200%" height="200%">
              <feGaussianBlur stdDeviation="2.5" result="blur" />
              <feComposite in="SourceGraphic" in2="blur" operator="over" />
            </filter>
            <linearGradient id="thinScan" x1="0" x2="0" y1="0" y2="1">
              <stop offset="0%" stopColor="#818cf8" stopOpacity="0" />
              <stop offset="50%" stopColor="#818cf8" stopOpacity="0.2" />
              <stop offset="100%" stopColor="#818cf8" stopOpacity="0" />
            </linearGradient>
          </defs>

          <style>
            {`
              @keyframes emergence {
                0% { opacity: 0; transform: translate(var(--startX), var(--startY)) scale(0.2); filter: blur(4px); }
                15% { opacity: 1; transform: translate(var(--endX), var(--endY)) scale(1); filter: blur(0px); }
                90% { opacity: 1; transform: translate(var(--endX), var(--endY)) scale(1); filter: blur(0px); }
                100% { opacity: 0; transform: translate(var(--endX), calc(var(--endY) - 20px)) scale(0.95); filter: blur(2px); }
              }
              .emerging-tag { animation: emergence 6s cubic-bezier(0.16, 1, 0.3, 1) forwards; }
              @keyframes organic-pulse {
                0% { fill-opacity: 0.1; transform: scale(0.8); }
                100% { fill-opacity: 0.7; transform: scale(1.1); }
              }
              .dot-organic { animation: organic-pulse 4s infinite alternate ease-in-out; }
            `}
          </style>

          {/* Sutil Scanline */}
          <rect x="0" y="0" width="512" height="60" fill="url(#thinScan)" opacity="0.3">
            <animate attributeName="y" values="-60;520" dur="10s" repeatCount="indefinite" />
          </rect>

          {/* Map of Dots */}
          <g filter="url(#softGlow)">
            {dots.map((dot, i) => (
              <circle 
                key={i} 
                cx={dot.x} 
                cy={dot.y} 
