import React, { useRef, useEffect } from 'react';
import { Particle } from '../types';

const AnimatedCanvas: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const mouseRef = useRef({ x: 0, y: 0, radius: 180 });

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let particles: Particle[] = [];
    // Aumentamos la cantidad para una red más densa
    const particleCount = 140;

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      particles = [];

      for (let i = 0; i < particleCount; i++) {
        const x = Math.random() * canvas.width;
        const y = Math.random() * canvas.height;
        // Colores profesionales: Índigo vibrante y Gris Pizarra
        const color = i % 3 === 0 ? '#6366f1' : '#94a3b8'; 
        particles.push({
          x,
          y,
          baseX: x,
          baseY: y,
          size: Math.random() * 2 + 1,
          density: (Math.random() * 30) + 1,
          color
        });
      }
    };

    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      for (let i = 0; i < particles.length; i++) {
        const p = particles[i];

        // Interacción con el mouse
        const dx = mouseRef.current.x - p.x;
        const dy = mouseRef.current.y - p.y;
        const distance = Math.sqrt(dx * dx + dy * dy);
        const forceDirectionX = dx / distance;
        const forceDirectionY = dy / distance;
        const maxDistance = mouseRef.current.radius;
        const force = (maxDistance - distance) / maxDistance;
        const directionX = forceDirectionX * force * p.density * 0.5;
        const directionY = forceDirectionY * force * p.density * 0.5;

        if (distance < mouseRef.current.radius) {
          p.x -= directionX;
          p.y -= directionY;
        } else {
          if (p.x !== p.baseX) {
            const dx_base = p.x - p.baseX;
            p.x -= dx_base / 30;
          }
          if (p.y !== p.baseY) {
            const dy_base = p.y - p.baseY;
            p.y -= dy_base / 30;
          }
        }

        // Dibujar conexiones de red - Intensificadas
        for (let j = i + 1; j < particles.length; j++) {
          const p2 = particles[j];
          const distSq = Math.pow(p.x - p2.x, 2) + Math.pow(p.y - p2.y, 2);
          const maxDistSq = 170 * 170;

          if (distSq < maxDistSq) {
            const dist = Math.sqrt(distSq);
            // Opacidad base aumentada para que se note el efecto de red
            const opacity = 0.25 * (1 - dist / 170);
            ctx.strokeStyle = `rgba(129, 140, 248, ${opacity})`;
            ctx.lineWidth = 0.8;
            ctx.beginPath();
            ctx.moveTo(p.x, p.y);
            ctx.lineTo(p2.x, p2.y);
            ctx.stroke();
          }
        }

        // Dibujar partícula
        ctx.fillStyle = p.color;
        ctx.globalAlpha = 0.6;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 1;

        // Flotación sutil constante
        p.baseX += Math.sin(Date.now() / 4000 + i) * 0.08;
        p.baseY += Math.cos(Date.now() / 4000 + i) * 0.08;
      }

      requestAnimationFrame(animate);
    };

