          <span className="ml-3 font-bold text-xl text-slate-800 tracking-tight">EduMap <span className="text-indigo-500">MX</span></span>
        </div>

        <nav className="flex-1 flex flex-col gap-2 p-4 overflow-y-auto custom-scroll">
          {menu.map((item) => {
            const isActive = location.pathname === item.path;
            return (
              <Link 
                key={item.path} 
                to={item.path}
                className={`flex items-center gap-3 p-3 rounded-xl transition-all duration-300 group ${
                  isActive 
                    ? 'bg-indigo-50 text-indigo-600 shadow-sm font-bold' 
                    : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800 font-medium'
                }`}
              >
                <item.icon size={22} className={`transition-transform group-hover:scale-110 ${isActive ? 'stroke-[2.5px]' : ''}`} />
                <span>{item.name}</span>
              </Link>
            )
          })}
        </nav>

        {/* User Session */}
        <div className="p-4 border-t border-slate-100">
            {user ? (
                <div className="bg-slate-50 rounded-xl p-3 border border-slate-100">
                    <div className="flex items-center gap-3 mb-3">
                        <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 font-bold border-2 border-white shadow-sm overflow-hidden">
                            {user.avatar ? <img src={user.avatar} className="w-full h-full object-cover" /> : <User size={20} />}
                        </div>
                        <div className="overflow-hidden">
                            <p className="text-sm font-bold text-slate-800 truncate">{user.name}</p>
                            <p className="text-xs text-slate-500 capitalize">{user.role}</p>
                        </div>
                    </div>
                    {user.role === 'student' && (
                        <Link to="/perfil" className="block text-center text-xs font-bold text-indigo-600 hover:underline mb-2">Mi Perfil</Link>
                    )}
                    <button onClick={logout} className="w-full py-1.5 text-xs text-red-500 bg-white border border-slate-200 rounded-lg font-medium hover:bg-red-50 transition-colors">
                        Cerrar Sesión
                    </button>
                </div>
            ) : (
                <button 
                    onClick={() => setIsLoginOpen(true)}
                    className="w-full py-3 bg-slate-900 text-white rounded-xl text-sm font-bold flex items-center justify-center gap-2 hover:bg-slate-800 transition-all shadow-lg"
                >
                    <LogIn size={16} /> Iniciar Sesión
                </button>
            )}
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full w-full relative min-w-0 bg-slate-100/50 overflow-hidden">
        {children}
      </main>

      {/* Mobile Nav */}
      <nav className="lg:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-200 h-16 z-[999] flex justify-around items-center px-2 pb-safe shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.05)]">
        {menu.map((item) => {
          const isActive = location.pathname === item.path;
          return (
            <Link 
              key={item.path} 
              to={item.path}
              className={`flex flex-col items-center justify-center w-full h-full gap-1 ${isActive ? 'text-indigo-600' : 'text-slate-400'}`}
            >
               <div className={`p-1.5 rounded-full transition-all ${isActive ? 'bg-indigo-50 -translate-y-1' : ''}`}>
                 <item.icon size={20} strokeWidth={isActive ? 2.5 : 2} />
               </div>
               <span className="text-[10px] font-medium">{item.name}</span>
            </Link>
          )
        })}
        <button 
            onClick={() => user ? (window.location.href = '#/perfil') : setIsLoginOpen(true)}
            className={`flex flex-col items-center justify-center w-full h-full gap-1 ${location.pathname === '/perfil' ? 'text-indigo-600' : 'text-slate-400'}`}
        >
            <div className={`p-1.5 rounded-full ${user ? 'bg-indigo-100 text-indigo-700' : ''}`}>
                <User size={20} />
            </div>
            <span className="text-[10px] font-medium">{user ? 'Perfil' : 'Login'}</span>
        </button>
      </nav>
    </div>
  );
};

export default Layout;

import React, { useEffect, useState } from 'react';
// Fix: Use direct named import for Link to improve compatibility
import { Link } from 'react-router-dom';
import { getInstituciones, getOfertas } from '../api';
import { Institucion, Oferta } from '../types';
import { MapPin, ChevronRight, Search, Building2 } from 'lucide-react';

const InstitutionsList: React.FC = () => {
  const [instituciones, setInstituciones] = useState<Institucion[]>([]);
  const [allOfertas, setAllOfertas] = useState<Oferta[]>([]);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    const loadData = async () => {
      try {
        const insts = await getInstituciones();
        const ofertas = await getOfertas();
        setInstituciones(insts || []);
        setAllOfertas(ofertas || []);
      } catch (error) {
        console.error("Failed to load list data", error);
      }
    };
    loadData();
  }, []);

  // Helper function to extract institution details and stats
  const getInstDetails = (instId: number) => {
    const instOfertas = allOfertas.filter(o => o.inst_id === instId);

    // Safety check for potential undefined nested objects (municipio, modalidad)
    const municipios = Array.from(new Set(
        instOfertas.map(o => o.municipio?.nombre).filter(Boolean)
    )).slice(0, 2);

    const municipiosStr = municipios.length > 0 
        ? municipios.join(', ')
        : 'Ubicación no especificada';

    const modalidades = Array.from(new Set(
        instOfertas.map(o => o.modalidad?.nombre).filter(Boolean)
    ));

    // Get Top 3 Careers for preview
    const topCarreras = instOfertas.slice(0, 3);

    return { count: instOfertas.length, municipiosStr, modalidades, topCarreras };
  };

  const filteredInstituciones = instituciones.filter(inst => 
    inst.nombre.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (inst.siglas && inst.siglas.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  return (
    <div className="flex-1 overflow-y-auto bg-slate-50 p-6 lg:p-10 pb-24">
      <div className="max-w-6xl mx-auto">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-4 mb-8">
            <div>
                <h1 className="text-3xl font-black text-slate-800">Instituciones</h1>
                <p className="text-slate-500">Explora universidades y centros educativos en el estado.</p>
            </div>
            <div className="relative w-full md:w-80">
                <Search className="absolute left-3 top-2.5 text-slate-400" size={18} />
                <input 
                    type="text" 
                    placeholder="Filtrar por nombre..." 
                    className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500/20 text-sm"
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                />
            </div>
        </div>

        {filteredInstituciones.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-slate-200">
            <Building2 className="mx-auto text-slate-300 mb-4" size={48} />
            <h3 className="text-lg font-medium text-slate-600">No se encontraron instituciones</h3>
            <p className="text-slate-400 text-sm">Prueba con otro término de búsqueda.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredInstituciones.map((inst) => {
              const details = getInstDetails(inst.id_institucion);
              return (
                <Link 
                  to={`/instituciones/${inst.id_institucion}`} 
                  key={inst.id_institucion}
                  className="bg-white rounded-2xl shadow-sm border border-slate-100 p-6 hover:shadow-xl hover:border-indigo-100 transition-all group flex flex-col h-full animate-fade-in"
                >
                  <div className="flex items-start justify-between mb-4">
                    <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-white font-bold text-lg shadow-sm overflow-hidden border border-slate-100 bg-white">
                      {inst.logoUrl ? <img src={inst.logoUrl} className="w-full h-full object-cover" alt={inst.nombre}/> : <span className="text-slate-600">{inst.siglas || 'U'}</span>}
                    </div>
                    <span className="bg-indigo-50 text-indigo-600 text-[10px] font-black px-2 py-1 rounded-full uppercase tracking-wider">
                      {details.count} Programas
                    </span>
                  </div>

                  <h3 className="font-bold text-lg text-slate-800 mb-1 leading-tight group-hover:text-indigo-600 transition-colors">
                    {inst.nombre}
                  </h3>

                  <div className="flex items-center text-xs text-slate-400 mb-4 font-medium">
                     <MapPin size={12} className="mr-1"/> {details.municipiosStr}
                  </div>

                  <div className="flex-1 space-y-2 mb-6">
                      {details.topCarreras.length > 0 ? (
                          <>
                              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Oferta destacada:</p>
                              {details.topCarreras.map(o => (
                                  <div key={o.id_oferta} className="flex items-center gap-2 text-xs text-slate-600">
                                      <div className="w-1 h-1 bg-indigo-400 rounded-full"></div>
                                      <span className="truncate">{o.carrera.nombre}</span>
                                  </div>
                              ))}
                          </>
                      ) : (
                        <p className="text-[10px] text-slate-300 italic">Sin oferta registrada</p>
                      )}
                  </div>

                  <div className="flex justify-between items-center pt-4 border-t border-slate-50">
                      <div className="flex gap-1">
                         {details.modalidades.slice(0, 2).map(m => (
                             <span key={m} className="text-[9px] bg-slate-50 text-slate-500 px-1.5 py-0.5 rounded border border-slate-200 font-bold uppercase">
                                 {m}
                             </span>
                         ))}
                      </div>
                      <div className="text-indigo-600 group-hover:translate-x-1 transition-transform">
                          <ChevronRight size={20} />
                      </div>
                  </div>
                </Link>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

export default InstitutionsList;
